#include <stdio.h>
#include <stdlib.h>

void findSingleNumbers(int *arr, int n, int *x, int *y) {
    int xorAll = 0;
    for (int i = 0; i < n; ++i) xorAll ^= arr[i];
    int diffBit = xorAll & -xorAll; // rightmost set bit
    int a = 0, b = 0;
    for (int i = 0; i < n; ++i) {
        if (arr[i] & diffBit) a ^= arr[i];
        else b ^= arr[i];
    }
    if (a > b) { *x = b; *y = a; }
    else { *x = a; *y = b; }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int tc = 0; tc < T; ++tc) {
        int n;
        scanf("%d", &n);
        int *arr = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        int a, b;
        findSingleNumbers(arr, n, &a, &b);
        printf("[%d, %d]\n", a, b);
        free(arr);
    }
    return 0;
}

