#include <bits/stdc++.h>
using namespace std;

pair<int,int> findSingleNumbers(const vector<int>& nums) {
    int xorAll = 0;
    for (int v : nums) xorAll ^= v;
    int diffBit = xorAll & -xorAll;
    int a = 0, b = 0;
    for (int v : nums) {
        if (v & diffBit) a ^= v; else b ^= v;
    }
    if (a > b) swap(a,b);
    return {a,b};
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T; if(!(cin>>T)) return 0;
    for(int tc=0; tc<T; ++tc){
        int n;
        cin >> n;
        vector<int> nums(n);
        for (int i = 0; i < n; ++i) cin >> nums[i];
        auto res = findSingleNumbers(nums);
        cout << '[' << res.first << ", " << res.second << "]\n";
    }
    return 0;
}

