import sys

def findSingleNumbers(nums):
    xor_all = 0
    for x in nums:
        xor_all ^= x
    diff_bit = xor_all & -xor_all
    a = b = 0
    for x in nums:
        if x & diff_bit:
            a ^= x
        else:
            b ^= x
    return sorted([a, b])

def main():
    data = sys.stdin.read().strip().split('\n')
    if not data:
        return
    T = int(data[0].strip())
    idx = 1
    for _ in range(T):
        while idx < len(data) and data[idx].strip() == '':
            idx += 1
        nums = list(map(int, data[idx].strip().split()))
        idx += 1
        a, b = findSingleNumbers(nums)
        print(f'[{a}, {b}]')

if __name__ == "__main__":
    main()

